SELECT ?locationLabel ?geographicLevel ?cityClass ?incomeClass ?urbanRuralStatus ?district ?population2024
WHERE {
  ?loc a :Location ;
       rdfs:label ?locationLabel .

  # Determine the specific geographic level of the location
  { ?loc a :Region ; BIND("Region") AS ?geographicLevel }
  UNION
  { ?loc a :Province ; BIND("Province") AS ?geographicLevel }
  UNION
  { ?loc a :City ; BIND("City") AS ?geographicLevel }
  UNION
  { ?loc a :Municipality ; BIND("Municipality") AS ?geographicLevel }
  UNION
  { ?loc a :Barangay ; BIND("Barangay") AS ?geographicLevel } .

  # Link to administrative details
  OPTIONAL { ?loc :hasDistrictName ?district . }
  OPTIONAL { ?loc :hasCityClass ?cityClass . }
  OPTIONAL { ?loc :hasIncomeClass ?incomeClass . }
  OPTIONAL { ?loc :hasUrbanRuralStatus ?urbanRuralStatus . }

  # Retrieve 2024 population data
  OPTIONAL {
    ?loc :hasPopulationData ?popInfo .
    ?popInfo :year "2024"^^xsd:integer ; # Constraint the year early
              :populationValue ?population2024 .
  }

}

